    {"path":"src/modules/tasks/service.js","content":"import { sendError } from '../../lib/errors';
import { randomUUID } from 'node:crypto';
import { projects } from '../projects/service';

export const taskStatuses = ['todo'];

export function createTask(projectId, { title, description }) {
  if (!title || !description) throw new Error('Title and description are required');
  const project = projects.find(p => p.id === projectId);
  if (!project) throw new Error('Project not found');
  const task = { id: randomUUID(), title, description, status: 'todo' };
  project.tasks.push(task);
  return task;
}

export function updateTaskStatus(projectId, taskId, status) {
  if (!['todo', 'done'].includes(status)) throw new Error('Invalid task status');
  const project = projects.find(p => p.id === projectId);
  if (!project) throw new Error('Project not found');
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) throw new Error('Task not found');
  task.status = status;
  return task;
}

export function getTasks(projectId, status) {
  const project = projects.find(p => p.id === projectId);
  if (!project) throw new Error('Project not found');
  if (status && !['todo', 'done'].includes(status)) throw new Error('Invalid task status');
  return status ? project.tasks.filter(t => t.status === status) : project.tasks;
}
